}

const SocialButton: React.FC<{
  provider: OAuthProvider
  onClick: () => void
  disabled: boolean
  variant: string
}> = ({ provider, onClick, disabled, variant }) => {
  const config = OAUTH_PROVIDERS[provider]
  const Icon = SocialIcons[config.icon as keyof typeof SocialIcons]

  const getButtonText = () => {
    switch (variant) {
      case "register":
        return `Sign up with ${config.name}`
      case "link":
        return `Link ${config.name}`
      default:
        return `Continue with ${config.name}`
    }
  }

  return (
    <button
      className={cn(
        "w-full flex items-center justify-center gap-3 h-12 text-sm font-medium rounded-[14px] border transition-colors disabled:opacity-50",
        PROVIDER_STYLES[provider] ?? ""
      )}
      onClick={onClick}
      disabled={disabled}
    >
      <Icon />
      <span>{getButtonText()}</span>
    </button>
  )
}

export const SocialLoginButtons: React.FC<SocialLoginButtonsProps> = ({
  returnUrl,
  className = "",
  disabled = false,
  variant = "login",
  onError,
}) => {
  const [loadingProvider, setLoadingProvider] = useState<OAuthProvider | null>(null)

  const handleSocialLogin = async (provider: OAuthProvider) => {
    if (disabled || loadingProvider) return

    try {
      setLoadingProvider(provider)
      await initiateOAuthLogin(provider, returnUrl)
    } catch (error: any) {
      console.error(`${provider} login error:`, error)
      onError?.(error.message || `Failed to initiate ${provider} login`)
      setLoadingProvider(null)
    }
  }

  const providers: OAuthProvider[] = ["google", "discord", "microsoft"]

  return (
    <div className={cn("space-y-3", className)}>
      <div className="grid grid-cols-1 gap-3">
        {providers.map((provider) => (
          <SocialButton
            key={provider}
            provider={provider}
            onClick={() => handleSocialLogin(provider)}
            disabled={disabled || loadingProvider === provider}
            variant={variant}
          />
        ))}
      </div>

      {loadingProvider && (
        <div className="text-center text-sm text-secondary">
          Redirecting to {OAUTH_PROVIDERS[loadingProvider].name}...
        </div>
      )}
    </div>
  )
}

import { z } from "zod"

export const loginFormSchema = z.object({
  email: z.string().nonempty("Please enter email").email("Invalid email"),
  password: z.string().nonempty("Please enter password"),
})

export type LoginFormData = z.infer<typeof loginFormSchema>

import { ProfilePage } from "@/components/profile/ProfilePage"
import { retrieveCustomer, getCustomerProfile } from "@/lib/data/customer"
import { listRegions } from "@/lib/data/regions"
import { redirect } from "next/navigation"

interface UserPageProps {
  searchParams: Promise<{
    error?: string
    provider?: string
    message?: string
  }>
}

export default async function UserPage({ searchParams }: UserPageProps) {
  const params = await searchParams

  // If there are OAuth error params, redirect to /login with them preserved
  if (params.error) {
    const loginParams = new URLSearchParams()
    if (params.error) loginParams.set("error", params.error)
    if (params.provider) loginParams.set("provider", params.provider)
    if (params.message) loginParams.set("message", params.message)
    redirect(`/login?${loginParams.toString()}`)
  }

  const user = await retrieveCustomer()

  if (!user) {
    redirect("/login")
  }

  const [customerProfile, regions] = await Promise.all([
    getCustomerProfile(user.id),
    listRegions(),
  ])

  return (
    <main>
      <ProfilePage
        user={user}
        customerProfile={customerProfile}
        regions={regions ?? []}
      />
    </main>
  )
}

"use client"

import { Card } from "@/components/atoms"
import { cn } from "@/lib/utils"
import { useEffect, useState } from "react"
import { CheckCircle } from "@medusajs/icons"

function validatePassword(password: string) {
  const errors = {
    tooShort: password.length < 8,
    noLower: !/[a-z]/.test(password),
    noUpper: !/[A-Z]/.test(password),
    noDigitOrSymbol: !/[0-9!@#$%^&*(),.?":{}|<>_\-+=\[\]\\\/~`]/.test(password),
  }

  return {
    isValid: !Object.values(errors).some(Boolean),
    errors,
  }
}

export const PasswordValidator = ({
  password,
  setError,
}: {
  password: string
  setError: (error: any) => void
}) => {
  const [newPasswordError, setNewPasswordError] = useState({
    isValid: false,
    lower: false,
    upper: false,
    "8chars": false,
    symbolOrDigit: false,
  })

  useEffect(() => {
    const validation = validatePassword(password)

    setError({
      isValid: validation.isValid,
      lower: validation.errors.noLower,
      upper: validation.errors.noUpper,
      "8chars": validation.errors.tooShort,
      symbolOrDigit: validation.errors.noDigitOrSymbol,
    })
    setNewPasswordError({
      isValid: validation.isValid,
      lower: validation.errors.noLower,
      upper: validation.errors.noUpper,
      "8chars": validation.errors.tooShort,
      symbolOrDigit: validation.errors.noDigitOrSymbol,
    })
  }, [password])
  return (
    <Card className="p-4">
      <p
        className={cn(
          "label-md flex items-center gap-2 mb-2",
          newPasswordError["8chars"] ? "text-red-700" : "text-green-700"
        )}
      >
        <CheckCircle /> At least 8 characters
      </p>
      <p
        className={cn(
          "label-md flex items-center gap-2 mb-2",
          newPasswordError["lower"] ? "text-red-700" : "text-green-700"
        )}
      >
        <CheckCircle /> One lowercase letter
      </p>
      <p
        className={cn(
          "label-md flex items-center gap-2 mb-2",
          newPasswordError["upper"] ? "text-red-700" : "text-green-700"
        )}
      >
        <CheckCircle /> One uppercase letter
      </p>
      <p
        className={cn(
          "label-md flex items-center gap-2 mb-2",
          newPasswordError["symbolOrDigit"] ? "text-red-700" : "text-green-700"
        )}
      >
        <CheckCircle /> One number or symbol
      </p>
    </Card>
  )
}

import { checkRegion } from "@/lib/helpers/check-region"
import { redirect } from "next/navigation"

export default async function AuthLayout({
  children,
  params,
}: Readonly<{
  children: React.ReactNode
  params: Promise<{ locale: string }>
}>) {
  const { locale } = await params
  const regionCheck = await checkRegion(locale)

  if (!regionCheck) {
    return redirect("/")
  }

  return <div className="min-h-screen bg-base">{children}</div>
}

